import type { SudokuBoard } from '@algorithm.ts/sudoku'
import cn from 'clsx'
import React, { useMemo } from 'react'
import './style.styl'
import type { SudokuBoardCell } from './types'

export type CellClickHandler = (
  cell: SudokuBoardCell,
  e: React.MouseEvent<HTMLElement>,
) => void

export interface SudokuBoardComponentProps {
  /**
   * Size of the child puzzle matrix (sqrt of original puzzle size).
   */
  childMatrixSize: number
  /**
   * segmentCodeMap is a mapping table for quickly located the sub-matrix of a
   * grid.
   */
  segmentNoMap: number[]
  /**
   * Sudoku puzzle.
   */
  puzzle: Readonly<SudokuBoard>
  /**
   * An attempt at a puzzle.
   */
  attempt: Readonly<SudokuBoard>
  /**
   * Duplicated grids
   */
  duplicatedMap?: boolean[][]
  /**
   * Activated cell.
   */
  activatedCell: SudokuBoardCell
  /**
   * @default 10
   */
  digitalBase?: number
  /**
   * The number on which grid shows the prompt content
   */
  hintGrid?: SudokuBoardCell
  /**
   * CSS class name.
   */
  className?: string
  /**
   * Sudoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * Callback function triggered when a grid is clicked.
   */
  onCellClick: CellClickHandler
}

/**
 * Render a sudoku board.
 *
 * @param props
 * @returns
 */
export const SudokuBoardComponent: React.FC<SudokuBoardComponentProps> =
  props => {
    const {
      childMatrixSize: SUDOKU_SIZE_SQRT,
      segmentNoMap,
      puzzle,
      attempt,
      duplicatedMap,
      digitalBase = 10,
      hintGrid,
      activatedCell,
      className,
      overlay,
      onCellClick,
    } = props

    // Sudoku thickness boarder borders.
    const borders = useMemo<React.ReactNode[]>(() => {
      const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
      const borders: React.ReactNode[] = []
      for (
        let i = SUDOKU_SIZE_SQRT, j = -1;
        i < SUDOKU_SIZE;
        i += SUDOKU_SIZE_SQRT, ++j
      ) {
        const position = `calc(${i} * var(--sudoku-board__cell-size) + ${
          i + j
        }px)`
        borders.push(
          <div
            key={`h-${i}`}
            className="sudoku-board__horizontal-border"
            style={{ top: position }}
          />,
        )
        borders.push(
          <div
            key={`v-${i}`}
            className="sudoku-board__vertical-border"
            style={{ left: position }}
          />,
        )
      }
      return borders
    }, [SUDOKU_SIZE_SQRT])

    const { r: R, c: C } = activatedCell
    const R0 = R === -1 ? -1 : segmentNoMap[R]
    const C0 = C === -1 ? -1 : segmentNoMap[C]
    const V = R === -1 ? -1 : attempt[R][C]
    const hintGridR = hintGrid === undefined ? -1 : hintGrid.r
    const hintGridC = hintGrid === undefined ? -1 : hintGrid.c
    const hintGridV = hintGrid === undefined ? undefined : hintGrid.v
    return (
      <div className={cn('sudoku-board', className)}>
        <div key="overlay" className={'sudoku-board__overlay'}>
          {overlay}
        </div>
        {borders}
        <div key="wrapper" className="sudoku-board__wrapper">
          {attempt.map((row, r) => (
            <div key={r} className="sudoku-board__row">
              {row.map((v, c) => {
                const isDuplicated: boolean =
                  duplicatedMap !== undefined && duplicatedMap[r][c]
                const isHintGrid: boolean =
                  hintGridV !== undefined && r === hintGridR && c === hintGridC

                const r0: number = segmentNoMap[r]
                const c0: number = segmentNoMap[c]
                const isActivated: boolean = r === R && c === C
                const isRelated: boolean =
                  !isActivated &&
                  (r === R || c === C || (r0 === R0 && c0 === C0))
                const isSame: boolean =
                  V === -1 ? false : !isRelated && !isActivated && v === V

                const vv = isHintGrid ? hintGridV! : v
                return (
                  <span
                    key={c}
                    className={cn('sudoku-board__cell', {
                      'sudoku-board__cell--left-seamless': c === 0,
                      'sudoku-board__cell--left':
                        c > 0 && c % SUDOKU_SIZE_SQRT === 0,
                      'sudoku-board__cell--top-seamless': r === 0,
                      'sudoku-board__cell--top':
                        r > 0 && r % SUDOKU_SIZE_SQRT === 0,
                      'sudoku-board__cell--preset': v !== -1,
                      'sudoku-board__cell--attempt': v !== puzzle[r][c],
                      'sudoku-board__cell--duplicated': isDuplicated,
                      'sudoku-board__cell--hint': isHintGrid,
                      'sudoku-board__cell--activated': isActivated,
                      'sudoku-board__cell--related': isRelated,
                      'sudoku-board__cell--same': isSame,
                    })}
                    onClick={e => onCellClick({ r, c }, e)}
                  >
                    <span className="sudoku-board__cell-content">
                      {vv === -1 ? '' : (vv + 1).toString(digitalBase)}
                    </span>
                  </span>
                )
              })}
            </div>
          ))}
        </div>
      </div>
    )
  }

SudokuBoardComponent.displayName = 'SudokuBoard'
export default SudokuBoardComponent
